  ('real-estate-moex-02176', 'real-estate', 'real-estate-moex-099-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '當估價師進行不動產估價時，對於附有違章建築之房地估價，有關違建部分是否需要評估呢？', '["違建部分一定要評估。並需就合法建物及違建部分於估價報告書中合併計算其價值", "違建部分不予以評估。但委託人要求評估其價值，並就合法建物及違建部分於估價報告書中分別標示各該部分之價格者，不在此限", "違建部分一定要評估。但委託人要求評估其價值，可就合法建物及違建部分於估價報告書中分別標示各該部分之價格者", "違建部分不予以評估。但受託人可自行斟酌其價值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "f6ed54d94d38", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產估價概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
